class NetworkManager {
    static let shared = NetworkManager()
    private var session: URLSession
    private let encryptionKey: SymmetricKey
    
    private init() {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.waitsForConnectivity = true
        
        self.session = URLSession(configuration: config, delegate: CertificatePinningDelegate(), delegateQueue: nil)
        
        if let keyData = KeychainManager.shared.load(key: "encryption_key") {
            self.encryptionKey = SymmetricKey(data: keyData)
        } else {
            self.encryptionKey = EncryptionManager.shared.generateKey()
            let keyData = self.encryptionKey.withUnsafeBytes { Data($0) }
            _ = KeychainManager.shared.save(key: "encryption_key", data: keyData)
        }
    }
    
    func request<T: Decodable>(endpoint: String, method: String = "GET", body: Data? = nil, token: String? = nil) async throws -> T {
        guard SecurityManager.shared.isDeviceSecure() else {
            throw NetworkError.insecureDevice
        }
        
        guard let url = URL(string: SecurityConfig.apiBaseURL + endpoint) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        if let token = token {
            let encryptedToken = try encryptToken(token)
            request.setValue("Bearer \(encryptedToken)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            request.httpBody = try EncryptionManager.shared.encrypt(data: body, key: encryptionKey)
            request.setValue("encrypted", forHTTPHeaderField: "X-Content-Encoding")
        }
        
        let (data, response) = try await session.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.invalidResponse
        }
        
        guard (200...299).contains(httpResponse.statusCode) else {
            throw NetworkError.httpError(httpResponse.statusCode)
        }
        
        let decryptedData = try EncryptionManager.shared.decrypt(data: data, key: encryptionKey)
        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(T.self, from: decryptedData)
    }
    
    private func encryptToken(_ token: String) throws -> String {
        let tokenData = token.data(using: .utf8)!
        let encrypted = try EncryptionManager.shared.encrypt(data: tokenData, key: encryptionKey)
        return encrypted.base64EncodedString()
    }
}

class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        guard SecurityConfig.certificatePinning else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let policies = [SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)]
        SecTrustSetPolicies(serverTrust, policies as CFTypeRef)
        
        var secresult = SecTrustResultType.invalid
        let status = SecTrustEvaluate(serverTrust, &secresult)
        
        if status == errSecSuccess {
            if let serverCertificate = SecTrustGetCertificateAtIndex(serverTrust, 0) {
                let serverCertificateData = SecCertificateCopyData(serverCertificate) as Data
                let pinnedCertificateData = getPinnedCertificate()
                
                if serverCertificateData == pinnedCertificateData {
                    let credential = URLCredential(trust: serverTrust)
                    completionHandler(.useCredential, credential)
                    return
                }
            }
        }
        
        completionHandler(.cancelAuthenticationChallenge, nil)
    }
    
    private func getPinnedCertificate() -> Data {
        if let certPath = Bundle.main.path(forResource: "certificate", ofType: "cer"),
           let certData = try? Data(contentsOf: URL(fileURLWithPath: certPath)) {
            return certData
        }
        return Data()
    }
}

