class PortfolioManager: ObservableObject {
    static let shared = PortfolioManager()
    @Published var portfolio: Portfolio?
    
    private init() {}
    
    func fetchPortfolio() async throws {
        guard let token = AuthenticationManager.shared.currentUser?.token else {
            throw PortfolioError.notAuthenticated
        }
        
        let portfolio: Portfolio = try await NetworkManager.shared.request(
            endpoint: "/portfolio",
            token: token
        )
        
        await MainActor.run {
            self.portfolio = portfolio
        }
    }
    
    func updateHolding(symbol: String, quantity: Int, price: Double) {
        guard var portfolio = portfolio else { return }
        
        if let index = portfolio.holdings.firstIndex(where: { $0.stockSymbol == symbol }) {
            var holding = portfolio.holdings[index]
            let totalCost = holding.averagePrice * Double(holding.quantity)
            let newCost = price * Double(quantity)
            let newQuantity = holding.quantity + quantity
            
            holding.quantity = newQuantity
            holding.averagePrice = (totalCost + newCost) / Double(newQuantity)
            portfolio.holdings[index] = holding
        } else {
            let newHolding = Holding(
                id: UUID().uuidString,
                stockSymbol: symbol,
                stockName: symbol,
                quantity: quantity,
                averagePrice: price,
                currentPrice: price,
                totalValue: price * Double(quantity),
                gainLoss: 0,
                gainLossPercent: 0
            )
            portfolio.holdings.append(newHolding)
        }
        
        self.portfolio = portfolio
    }
}

