class MarketDataManager: ObservableObject {
    static let shared = MarketDataManager()
    @Published var stocks: [Stock] = []
    @Published var watchlist: [Stock] = []
    
    private var cancellables = Set<AnyCancellable>()
    private var webSocketTask: URLSessionWebSocketTask?
    
    private init() {}
    
    func fetchStocks() async throws {
        guard let token = AuthenticationManager.shared.currentUser?.token else {
            throw MarketDataError.notAuthenticated
        }
        
        let stocks: [Stock] = try await NetworkManager.shared.request(
            endpoint: "/market/stocks",
            token: token
        )
        
        await MainActor.run {
            self.stocks = stocks
        }
    }
    
    func searchStocks(query: String) async throws -> [Stock] {
        guard let token = AuthenticationManager.shared.currentUser?.token else {
            throw MarketDataError.notAuthenticated
        }
        
        let stocks: [Stock] = try await NetworkManager.shared.request(
            endpoint: "/market/search?q=\(query)",
            token: token
        )
        
        return stocks
    }
    
    func connectWebSocket() {
        guard let url = URL(string: "wss://api.tradingplatform.com/ws/market") else { return }
        
        webSocketTask = URLSession.shared.webSocketTask(with: url)
        webSocketTask?.resume()
        receiveMessage()
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMarketUpdate(text)
                case .data(let data):
                    self?.handleMarketUpdate(String(data: data, encoding: .utf8) ?? "")
                @unknown default:
                    break
                }
                self?.receiveMessage()
            case .failure(let error):
                print("WebSocket error: \(error)")
            }
        }
    }
    
    private func handleMarketUpdate(_ message: String) {
        guard let data = message.data(using: .utf8),
              let stock = try? JSONDecoder().decode(Stock.self, from: data) else {
            return
        }
        
        DispatchQueue.main.async {
            if let index = self.stocks.firstIndex(where: { $0.id == stock.id }) {
                self.stocks[index] = stock
            }
            
            if let index = self.watchlist.firstIndex(where: { $0.id == stock.id }) {
                self.watchlist[index] = stock
            }
        }
    }
    
    func disconnectWebSocket() {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
    }
}

enum MarketDataError: Error {
    case notAuthenticated
    case fetchFailed
}

