        contentView.addSubview(priceLabel)
        contentView.addSubview(changeLabel)
        contentView.addSubview(quantityTextField)
        contentView.addSubview(buyButton)
        contentView.addSubview(sellButton)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentView.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentView.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentView.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentView.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentView.widthAnchor.constraint(equalTo: scrollView.widthAnchor),
            
            priceLabel.centerXAnchor.constraint(equalTo: contentView.centerXAnchor),
            priceLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 40),
            
            changeLabel.centerXAnchor.constraint(equalTo: contentView.centerXAnchor),
            changeLabel.topAnchor.constraint(equalTo: priceLabel.bottomAnchor, constant: 8),
            
            quantityTextField.centerXAnchor.constraint(equalTo: contentView.centerXAnchor),
            quantityTextField.topAnchor.constraint(equalTo: changeLabel.bottomAnchor, constant: 40),
            quantityTextField.widthAnchor.constraint(equalToConstant: 300),
            quantityTextField.heightAnchor.constraint(equalToConstant: 44),
            
            buyButton.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 20),
            buyButton.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 30),
            buyButton.widthAnchor.constraint(equalToConstant: 140),
            buyButton.heightAnchor.constraint(equalToConstant: 44),
            
            sellButton.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -20),
            sellButton.topAnchor.constraint(equalTo: quantityTextField.bottomAnchor, constant: 30),
            sellButton.widthAnchor.constraint(equalToConstant: 140),
            sellButton.heightAnchor.constraint(equalToConstant: 44),
            sellButton.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -40)
        ])
    }
    
    @objc private func buyTapped() {
        executeTrade(type: .buy)
    }
    
    @objc private func sellTapped() {
        executeTrade(type: .sell)
    }
    
    private func executeTrade(type: TradeType) {
        guard let quantityText = quantityTextField.text,
              let quantity = Int(quantityText), quantity > 0 else {
            showAlert(message: "Please enter a valid quantity")
            return
        }
        
        let request = TradeRequest(
            stockSymbol: stock.symbol,
            type: type,
            quantity: quantity,
            price: stock.currentPrice
        )
        
        Task {
            do {
                let trade = try await TradingManager.shared.executeTrade(request: request)
                await MainActor.run {
                    self.showAlert(message: "Trade executed successfully!")
                    self.quantityTextField.text = ""
                }
            } catch {
                await MainActor.run {
                    self.showAlert(message: "Trade failed: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Trade", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

class PortfolioViewController: UIViewController, UITableViewDelegate, UITableViewDataSource {
    private let tableView = UITableView()
    private let headerView = UIView()
    private let totalValueLabel = UILabel()
    private let gainLossLabel = UILabel()
    private var holdings: [Holding] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        loadData()
    }
    
    private func setupUI() {
        title = "Portfolio"
        view.backgroundColor = .systemBackground
        
        headerView.backgroundColor = .systemGray6
        headerView.translatesAutoresizingMaskIntoConstraints = false
        
        totalValueLabel.font = .boldSystemFont(ofSize: 32)
        totalValueLabel.translatesAutoresizingMaskIntoConstraints = false
        
        gainLossLabel.font = .systemFont(ofSize: 18)
        gainLossLabel.translatesAutoresizingMaskIntoConstraints = false
        
        headerView.addSubview(totalValueLabel)
        headerView.addSubview(gainLossLabel)
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(HoldingCell.self, forCellReuseIdentifier: "HoldingCell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(headerView)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            headerView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            headerView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            headerView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            headerView.heightAnchor.constraint(equalToConstant: 120),
            
            totalValueLabel.centerXAnchor.constraint(equalTo: headerView.centerXAnchor),
            totalValueLabel.topAnchor.constraint(equalTo: headerView.topAnchor, constant: 20),
            
            gainLossLabel.centerXAnchor.constraint(equalTo: headerView.centerXAnchor),
            gainLossLabel.topAnchor.constraint(equalTo: totalValueLabel.bottomAnchor, constant: 8),
            
            tableView.topAnchor.constraint(equalTo: headerView.bottomAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    private func loadData() {
        Task {
            do {
                try await PortfolioManager.shared.fetchPortfolio()
                await MainActor.run {
                    if let portfolio = PortfolioManager.shared.portfolio {
                        self.updateHeader(portfolio: portfolio)
                        self.holdings = portfolio.holdings
                        self.tableView.reloadData()
                    }
                }
            } catch {
                print("Error loading portfolio: \(error)")
            }
        }
    }
    
    private func updateHeader(portfolio: Portfolio) {
        totalValueLabel.text = String(format: "$%.2f", portfolio.totalValue)
        
        let gainLossText = String(format: "$%.2f (%.2f%%)", portfolio.totalGainLoss, portfolio.totalGainLossPercent)
        gainLossLabel.text = portfolio.totalGainLoss >= 0 ? "+\(gainLossText)" : gainLossText
        gainLossLabel.textColor = portfolio.totalGainLoss >= 0 ? .systemGreen : .systemRed
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return holdings.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "HoldingCell", for: indexPath) as! HoldingCell
        cell.configure(with: holdings[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 90
    }
}

