class TradesViewController: UIViewController, UITableViewDelegate, UITableViewDataSource {
    private let segmentedControl = UISegmentedControl(items: ["Active", "History"])
    private let tableView = UITableView()
    private var activeTrades: [Trade] = []
    private var historyTrades: [Trade] = []
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        loadData()
    }
    
    private func setupUI() {
        title = "Trades"
        view.backgroundColor = .systemBackground
        
        segmentedControl.selectedSegmentIndex = 0
        segmentedControl.addTarget(self, action: #selector(segmentChanged), for: .valueChanged)
        segmentedControl.translatesAutoresizingMaskIntoConstraints = false
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(TradeCell.self, forCellReuseIdentifier: "TradeCell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(segmentedControl)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            segmentedControl.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            segmentedControl.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            segmentedControl.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            
            tableView.topAnchor.constraint(equalTo: segmentedControl.bottomAnchor, constant: 16),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
    }
    
    @objc private func segmentChanged() {
        tableView.reloadData()
    }
    
    private func loadData() {
        Task {
            do {
                try await TradingManager.shared.fetchActiveTrades()
                try await TradingManager.shared.fetchTradeHistory()
                await MainActor.run {
                    self.activeTrades = TradingManager.shared.activeTrades
                    self.historyTrades = TradingManager.shared.tradeHistory
                    self.tableView.reloadData()
                }
            } catch {
                print("Error loading trades: \(error)")
            }
        }
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return segmentedControl.selectedSegmentIndex == 0 ? activeTrades.count : historyTrades.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TradeCell", for: indexPath) as! TradeCell
        let trade = segmentedControl.selectedSegmentIndex == 0 ? activeTrades[indexPath.row] : historyTrades[indexPath.row]
        cell.configure(with: trade)
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 90
    }
}

