    }
    
    private func setupUI() {
        symbolLabel.font = .boldSystemFont(ofSize: 18)
        typeLabel.font = .systemFont(ofSize: 14)
        detailsLabel.font = .systemFont(ofSize: 14)
        detailsLabel.textColor = .secondaryLabel
        statusLabel.font = .systemFont(ofSize: 14)
        statusLabel.textAlignment = .right
        
        [symbolLabel, typeLabel, detailsLabel, statusLabel].forEach {
            $0.translatesAutoresizingMaskIntoConstraints = false
            contentView.addSubview($0)
        }
        
        NSLayoutConstraint.activate([
            symbolLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            symbolLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            
            typeLabel.leadingAnchor.constraint(equalTo: symbolLabel.trailingAnchor, constant: 8),
            typeLabel.centerYAnchor.constraint(equalTo: symbolLabel.centerYAnchor),
            
            detailsLabel.leadingAnchor.constraint(equalTo: symbolLabel.leadingAnchor),
            detailsLabel.topAnchor.constraint(equalTo: symbolLabel.bottomAnchor, constant: 4),
            
            statusLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            statusLabel.centerYAnchor.constraint(equalTo: contentView.centerYAnchor)
        ])
    }
    
    func configure(with trade: Trade) {
        symbolLabel.text = trade.stockSymbol
        typeLabel.text = trade.type.rawValue.uppercased()
        typeLabel.textColor = trade.type == .buy ? .systemGreen : .systemRed
        detailsLabel.text = "\(trade.quantity) shares @ $\(String(format: "%.2f", trade.price))"
        statusLabel.text = trade.status.rawValue.capitalized
        
        switch trade.status {
        case .executed:
            statusLabel.textColor = .systemGreen
        case .failed, .cancelled:
            statusLabel.textColor = .systemRed
        case .pending:
            statusLabel.textColor = .systemOrange
        }
    }
}

